import { useState, useEffect } from 'react';
import Header from '../pages/Header'; 

const ProfilePage = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  
  const [editMode, setEditMode] = useState(false);
  const [editUsername, setEditUsername] = useState('');
  const [editEmail, setEditEmail] = useState('');

  
  const [showPasswordForm, setShowPasswordForm] = useState(false);
  const [oldPassword, setOldPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  
  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {

  return (
    <>
      <Header />
      <div style={{ maxWidth: 1200, margin: '40px auto', padding: '0 20px' }}>
        {/* Сообщения об ошибках и успехе */}
        {error && (
          <div style={{ background: '#f8d7da', color: '#721c24', padding: '12px', borderRadius: 8, marginBottom: 20 }}>
            {error}
          </div>
        )}
        {success && (
          <div style={{ background: '#d4edda', color: '#155724', padding: '12px', borderRadius: 8, marginBottom: 20 }}>
            {success}
          </div>
        )}

        
        <div style={{
          display: 'flex',
          gap: '40px',
          background: '#E4E4E5',
          borderRadius: '16px',
          padding: '40px',
          boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
          marginBottom: '30px',
          flexWrap: 'wrap'
        }}>
          
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '15px',
            flex: '0 0 auto'
          }}>
            <div style={{
              width: '150px',
              height: '150px',
              borderRadius: '50%',
              background: '#BEBEBE',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '4px solid #949494',
              overflow: 'hidden'
            }}>
              {user.avatar ? (
                <img
                  src={user.avatar.startsWith('http') ? user.avatar : `/uploads/${user.avatar}`}
                  alt="Аватар"
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                />
              ) : (
                <span style={{ color: '#7A7A7A', fontSize: '18px', fontWeight: 600 }}>Аватар</span>
              )}
            </div>
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', justifyContent: 'center' }}>
              <label
                htmlFor="avatar-upload"
                style={{
                  padding: '10px 20px',
                  background: '#7A7A7A',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  fontSize: '14px',
                  cursor: 'pointer',
                  display: 'inline-block'
                }}
              >
                Загрузить фото
              </label>
              <input
                id="avatar-upload"
                type="file"
                accept="image/*"
                onChange={handleAvatarUpload}
                style={{ display: 'none' }}
              />
              {user.avatar && (
                <button
                  onClick={handleAvatarDelete}
                  style={{
                    padding: '10px 20px',
                    background: '#d9534f',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    fontSize: '14px',
                    cursor: 'pointer'
                  }}
                >
                  Удалить
                </button>
              )}
            </div>
          </div>

          
          <div style={{
            flex: 1,
            display: 'flex',
            flexDirection: 'column',
            gap: '20px',
            justifyContent: 'center'
          }}>
            {!editMode ? (
              
              <>
                <div style={{
                  display: 'flex',
                  gap: '10px',
                  fontSize: '18px',
                  paddingBottom: '10px',
                  borderBottom: '2px solid #BEBEBE',
                  alignItems: 'center'
                }}>
                  <span style={{ fontWeight: 600, color: '#545454', minWidth: '100px' }}>Никнейм:</span>
                  <span style={{ color: '#3C3C3C' }}>{user.username}</span>
                </div>
                <div style={{
                  display: 'flex',
                  gap: '10px',
                  fontSize: '18px',
                  paddingBottom: '10px',
                  borderBottom: '2px solid #BEBEBE',
                  alignItems: 'center'
                }}>
                  <span style={{ fontWeight: 600, color: '#545454', minWidth: '100px' }}>Email:</span>
                  <span style={{ color: '#3C3C3C' }}>{user.email}</span>
                </div>
                <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap', marginTop: '10px' }}>
                  <button
                    onClick={() => setEditMode(true)}
                    style={{
                      padding: '12px 30px',
                      background: '#949494',
                      color: 'white',
                      border: 'none',
                      borderRadius: '8px',
                      fontSize: '16px',
                      cursor: 'pointer'
                    }}
                  >
                    Редактировать профиль
                  </button>
                  <button
                    onClick={() => setShowPasswordForm(!showPasswordForm)}
                    style={{
                      padding: '12px 30px',
                      background: '#7A7A7A',
                      color: 'white',
                      border: 'none',
                      borderRadius: '8px',
                      fontSize: '16px',
                      cursor: 'pointer'
                    }}
                  >
                    {showPasswordForm ? 'Отмена' : 'Сменить пароль'}
                  </button>
                </div>
              </>
            ) : (
              
              <form onSubmit={handleUpdateProfile}>
                <div style={{ marginBottom: '15px' }}>
                  <label style={{ display: 'block', marginBottom: '5px', fontWeight: 500, color: '#545454' }}>
                    Никнейм
                  </label>
                  <input
                    type="text"
                    value={editUsername}
                    onChange={(e) => setEditUsername(e.target.value)}
                    required
                    style={{
                      width: '100%',
                      padding: '10px',
                      border: '2px solid #BEBEBE',
                      borderRadius: '8px',
                      fontSize: '16px',
                      boxSizing: 'border-box'
                    }}
                  />
                </div>
                <div style={{ marginBottom: '20px' }}>
                  <label style={{ display: 'block', marginBottom: '5px', fontWeight: 500, color: '#545454' }}>
                    Email
                  </label>
                  <input
                    type="email"
                    value={editEmail}
                    onChange={(e) => setEditEmail(e.target.value)}
                    required
                    style={{
                      width: '100%',
                      padding: '10px',
                      border: '2px solid #BEBEBE',
                      borderRadius: '8px',
                      fontSize: '16px',
                      boxSizing: 'border-box'
                    }}
                  />
                </div>
                <div style={{ display: 'flex', gap: '15px' }}>
                  <button
                    type="submit"
                    style={{
                      padding: '12px 30px',
                      background: '#7A7A7A',
                      color: 'white',
                      border: 'none',
                      borderRadius: '8px',
                      fontSize: '16px',
                      cursor: 'pointer'
                    }}
                  >
                    Сохранить
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      setEditMode(false);
                      setEditUsername(user.username);
                      setEditEmail(user.email);
                    }}
                    style={{
                      padding: '12px 30px',
                      background: '#BEBEBE',
                      color: '#3C3C3C',
                      border: 'none',
                      borderRadius: '8px',
                      fontSize: '16px',
                      cursor: 'pointer'
                    }}
                  >
                    Отмена
                  </button>
                </div>
              </form>
            )}
          </div>
        </div>

        
        {showPasswordForm && (
          <div style={{
            background: '#E4E4E5',
            borderRadius: '16px',
            padding: '30px',
            marginBottom: '30px',
            boxShadow: '0 4px 20px rgba(0,0,0,0.1)'
          }}>
            <h3 style={{ color: '#3C3C3C', marginBottom: '20px' }}>Смена пароля</h3>
            <form onSubmit={handleChangePassword}>
              <div style={{ marginBottom: '15px' }}>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 500, color: '#545454' }}>
                  Старый пароль
                </label>
                <input
                  type="password"
                  value={oldPassword}
                  onChange={(e) => setOldPassword(e.target.value)}
                  required
                  style={{
                    width: '100%',
                    padding: '10px',
                    border: '2px solid #BEBEBE',
                    borderRadius: '8px',
                    fontSize: '16px',
                    boxSizing: 'border-box'
                  }}
                />
              </div>
              <div style={{ marginBottom: '15px' }}>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 500, color: '#545454' }}>
                  Новый пароль
                </label>
                <input
                  type="password"
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  required
                  minLength="6"
                  style={{
                    width: '100%',
                    padding: '10px',
                    border: '2px solid #BEBEBE',
                    borderRadius: '8px',
                    fontSize: '16px',
                    boxSizing: 'border-box'
                  }}
                />
              </div>
              <div style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 500, color: '#545454' }}>
                  Подтверждение нового пароля
                </label>
                <input
                  type="password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  required
                  style={{
                    width: '100%',
                    padding: '10px',
                    border: '2px solid #BEBEBE',
                    borderRadius: '8px',
                    fontSize: '16px',
                    boxSizing: 'border-box'
                  }}
                />
              </div>
              <div style={{ display: 'flex', gap: '15px' }}>
                <button
                  type="submit"
                  style={{
                    padding: '12px 30px',
                    background: '#7A7A7A',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    fontSize: '16px',
                    cursor: 'pointer'
                  }}
                >
                  Сменить пароль
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setShowPasswordForm(false);
                    setOldPassword('');
                    setNewPassword('');
                    setConfirmPassword('');
                  }}
                  style={{
                    padding: '12px 30px',
                    background: '#BEBEBE',
                    color: '#3C3C3C',
                    border: 'none',
                    borderRadius: '8px',
                    fontSize: '16px',
                    cursor: 'pointer'
                  }}
                >
                  Отмена
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Блок матчей */}
        <div style={{
          background: '#E4E4E5',
          borderRadius: '16px',
          padding: '30px',
          boxShadow: '0 4px 20px rgba(0,0,0,0.1)'
        }}>
          <h3 style={{ color: '#3C3C3C', fontSize: '24px', marginBottom: '20px', paddingBottom: '15px', borderBottom: '3px solid #BEBEBE' }}>
            🎮 Запланированные матчи
          </h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {[1, 2, 3, 4].map((num) => (
              <div key={num} style={{
                background: 'white',
                padding: '20px',
                borderRadius: '12px',
                border: '2px dashed #BEBEBE',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                minHeight: '60px'
              }}>
                <span style={{ color: '#BEBEBE', fontSize: '16px', fontWeight: 500 }}>Матч #{num}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </>
  );
      try {
      setLoading(true);
      const response = await fetch('/api/profile', {
        credentials: 'include'
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка загрузки профиля');
      setUser(data.user);
      
      setEditUsername(data.user.username);
      setEditEmail(data.user.email);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  
  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('/api/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username: editUsername, email: editEmail }),
        credentials: 'include'
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка обновления');
      setUser(data.user);
      setSuccess('Профиль обновлён!');
      setEditMode(false);
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      setError(err.message);
      setTimeout(() => setError(''), 3000);
    }
  };

  // Смена пароля
  const handleChangePassword = async (e) => {
    e.preventDefault();
    if (newPassword !== confirmPassword) {
      setError('Пароли не совпадают');
      return;
    }
    if (newPassword.length < 6) {
      setError('Новый пароль должен быть минимум 6 символов');
      return;
    }
    try {
      const response = await fetch('/api/change-password', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ oldPassword, newPassword }),
        credentials: 'include'
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка смены пароля');
      setSuccess('Пароль успешно изменён!');
      setShowPasswordForm(false);
      setOldPassword('');
      setNewPassword('');
      setConfirmPassword('');
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      setError(err.message);
      setTimeout(() => setError(''), 3000);
    }
  };

  // Загрузка аватара
  const handleAvatarUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    // Проверка типа и размера
    if (!file.type.startsWith('image/')) {
      setError('Можно загружать только изображения');
      setTimeout(() => setError(''), 3000);
      return;
    }
    if (file.size > 2 * 1024 * 1024) {
      setError('Файл не должен превышать 2 МБ');
      setTimeout(() => setError(''), 3000);
      return;
    }

    const formData = new FormData();
    formData.append('avatar', file);

    try {
      const response = await fetch('/api/avatar', {
        method: 'POST',
        body: formData,
        credentials: 'include'
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка загрузки');
      setUser(data.user);
      setSuccess('Аватар загружен!');
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      setError(err.message);
      setTimeout(() => setError(''), 3000);
    }
    e.target.value = '';
  };

  const handleAvatarDelete = async () => {
    if (!user?.avatar) {
      setError('Аватар не установлен');
      return;
    }
    try {
      const response = await fetch('/api/avatar', {
        method: 'DELETE',
        credentials: 'include'
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка удаления');
      setUser(data.user);
      setSuccess('Аватар удалён');
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      setError(err.message);
      setTimeout(() => setError(''), 3000);
    }
  };

  // if (loading) return <div style={{ textAlign: 'center', marginTop: 50 }}>Загрузка...</div>;
  // if (!user) return <div style={{ textAlign: 'center', marginTop: 50 }}>Пользователь не найден</div>;

};

export default ProfilePage;
